Aero.comment=new Vue({el:"#comments",data:{loading:!0,contentId:null,items:[],state:"all"},computed:{filteredItems:function(){var t=this;return this.items.filter(function(e){return"all"===t.state||("pending"===t.state?!e.isApproved:e.isApproved)})}},methods:{load:function(t){var e=this;t||(t=""),fetch(Aero.baseUrl+"manager/api/comment/"+t).then(function(t){return t.json()}).then(function(t){e.contentId=t.contentId,e.items=t.comments}).catch(function(t){console.log("error:",t)})},approve:function(t){var e=this;fetch(Aero.baseUrl+"manager/api/comment/approve",{method:"post",headers:Aero.utils.antiForgeryHeaders(),body:JSON.stringify({id:t,parentId:e.contentId})}).then(function(t){return t.json()}).then(function(t){t.status&&Aero.notifications.push(t.status),e.contentId=t.contentId,e.items=t.comments}).catch(function(t){console.log("error:",t)})},unapprove:function(t){var e=this;fetch(Aero.baseUrl+"manager/api/comment/unapprove",{method:"post",headers:Aero.utils.antiForgeryHeaders(),body:JSON.stringify({id:t,parentId:e.contentId})}).then(function(t){return t.json()}).then(function(t){t.status&&Aero.notifications.push(t.status),e.contentId=t.contentId,e.items=t.comments}).catch(function(t){console.log("error:",t)})},toggleApproved:function(t){t.isApproved=!t.isApproved,t.isApproved?this.approve(t.id):this.unapprove(t.id)},remove:function(t){var e=this;fetch(Aero.baseUrl+"manager/api/comment/delete",{method:"delete",headers:Aero.utils.antiForgeryHeaders(),body:JSON.stringify(t)}).then(function(t){return t.json()}).then(function(t){Aero.notifications.push(t),e.load(e.contentId)}).catch(function(t){console.log("error:",t)})},setStatus:function(t){this.state=t}},updated:function(){this.loading=!1}});